// YFM v3.9
const API_BASE='https://youth-football-manager.vercel.app/api';
const STAGIONE_ID='22222222-2222-2222-2222-222222222222';
let squadraId='33333333-3333-3333-3333-333333333333',allSquadre=[],currentPage='dashboard',allPlayers=[],allMatches=[],workspaceInfo=null;

document.addEventListener('DOMContentLoaded',()=>{setupNavigation();setupMobileMenu();loadSquadre().then(()=>loadDashboard());loadWorkspaceInfo();});
function setupNavigation(){document.querySelectorAll('.sidebar-nav a').forEach(l=>l.addEventListener('click',e=>{e.preventDefault();document.querySelectorAll('.sidebar-nav a').forEach(x=>x.classList.remove('active'));l.classList.add('active');currentPage=l.dataset.page;navigateTo(currentPage);document.getElementById('sidebar').classList.remove('open');}));}
function setupMobileMenu(){document.getElementById('menuBtn').addEventListener('click',()=>document.getElementById('sidebar').classList.toggle('open'));}
function navigateTo(p){document.getElementById('pageContent').innerHTML='<div class="loading"><div class="spinner"></div>Caricamento...</div>';switch(p){case'dashboard':loadDashboard();break;case'roster':loadRoster();break;case'calendar':loadCalendar();break;case'training':loadTraining();break;case'reports':loadReports();break;case'settings':loadSettings();break;default:loadDashboard();}}
async function apiFetch(u,o={}){const r=await fetch(API_BASE+u,{headers:{'Content-Type':'application/json',...o.headers},...o});if(!r.ok)throw new Error('HTTP '+r.status);return r.json();}
function getAvatarColor(n){const C=['#1A365D','#2ECC71','#E74C3C','#F39C12','#2980B9','#8E44AD','#16A085','#D35400'];let h=0;for(let i=0;i<(n||'').length;i++)h=n.charCodeAt(i)+((h<<5)-h);return C[Math.abs(h)%C.length];}
function formatDate(d){if(!d)return'';return new Date(d).toLocaleDateString('it-IT',{weekday:'long',day:'numeric',month:'long',year:'numeric',hour:'2-digit',minute:'2-digit'});}
function formatDateShort(d){if(!d)return'';return new Date(d).toLocaleDateString('it-IT');}
function formatTime(t){if(!t)return'';return t.slice(0,5);}
function showLoading(){const d=document.createElement('div');d.id='globalLoading';d.innerHTML='<div style="position:fixed;inset:0;background:rgba(0,0,0,0.3);display:flex;align-items:center;justify-content:center;z-index:9999;"><div style="background:white;border-radius:16px;padding:32px;text-align:center;box-shadow:0 8px 32px rgba(0,0,0,0.2);"><div class="spinner"></div><p style="margin-top:12px;font-weight:500;">Salvataggio...</p></div></div>';document.body.appendChild(d);}
function hideLoading(){const d=document.getElementById('globalLoading');if(d)d.remove();}
function createModal(title,content,footer,mW){mW=mW||'600px';const ex=document.getElementById('currentModal');if(ex)ex.remove();const m=document.createElement('div');m.className='modal-overlay';m.id='currentModal';m.innerHTML='<div class="modal-content" style="max-width:'+mW+';"><div class="modal-header"><h2>'+title+'</h2><button class="modal-close-btn" id="modalCloseX">×</button></div><div class="modal-body">'+content+'</div>'+(footer?'<div class="modal-footer">'+footer+'</div>':'')+'</div>';document.body.appendChild(m);const close=()=>{const x=document.getElementById('currentModal');if(x)x.remove();};document.getElementById('modalCloseX').addEventListener('click',close);m.addEventListener('click',e=>{if(e.target===m)close();});window._closeModal=close;return{modal:m,closeModal:close};}
async function loadSquadre(){try{allSquadre=await apiFetch('/stagioni/'+STAGIONE_ID+'/squadre');const sel=document.getElementById('squadraSelect');if(sel){sel.innerHTML=allSquadre.map(s=>'<option value="'+s.id+'"'+(s.id===squadraId?' selected':'')+'>'+s.nome+'</option>').join('');sel.addEventListener('change',e=>{squadraId=e.target.value;allPlayers=[];allMatches=[];navigateTo(currentPage);});}if(allSquadre.length>0&&!allSquadre.find(s=>s.id===squadraId))squadraId=allSquadre[0].id;}catch(err){console.error(err);}}
async function loadWorkspaceInfo(){try{const w=await apiFetch('/workspaces');if(w&&w.length>0){workspaceInfo=w[0];document.getElementById('workspaceName').textContent=w[0].nome;const hn=document.getElementById('headerSocName');if(hn)hn.textContent=w[0].nome;const logo=document.getElementById('headerLogo');if(logo&&w[0].logo_url){logo.src=w[0].logo_url;logo.style.display='block';}}}catch(e){document.getElementById('workspaceName').textContent='ASD Albalonga';}}
function getSquadraName(){const s=allSquadre.find(x=>x.id===squadraId);return s?s.nome:'Squadra';}
function getSquadra(){return allSquadre.find(x=>x.id===squadraId)||{};}
function getSocietaName(){return workspaceInfo?workspaceInfo.nome:'ASD Albalonga';}
function updateLogo(){const url=prompt('URL logo:','https://');if(url){apiFetch('/workspaces/'+(workspaceInfo?workspaceInfo.id:'11111111-1111-1111-1111-111111111111')+'/logo',{method:'PUT',body:JSON.stringify({logo_url:url})}).then(()=>loadWorkspaceInfo()).catch(e=>alert('Errore: '+e.message));}}

// ── DASHBOARD ──
async function loadDashboard(){const c=document.getElementById('pageContent');try{const[stats,top]=await Promise.all([apiFetch('/squadre/'+squadraId+'/statistiche-complete').catch(()=>({punti:0,partiteGiocate:0,vittorie:0,pareggi:0,sconfitte:0,golFatti:0,golSubiti:0,differenzaReti:0,risultati:[]})),apiFetch('/squadre/'+squadraId+'/top-players').catch(()=>({marcatori:[],assistmen:[],presenze:[]}))]);const s=getSquadra();const widgets=[{i:'🏆',v:stats.punti,l:'Punti',c:'#27AE60'},{i:'📊',v:stats.partiteGiocate,l:'Giocate'},{i:'✅',v:stats.vittorie,l:'Vittorie',c:'#27AE60'},{i:'🤝',v:stats.pareggi,l:'Pareggi',c:'#F39C12'},{i:'❌',v:stats.sconfitte,l:'Sconfitte',c:'#E74C3C'},{i:'⚽',v:stats.golFatti,l:'GF'},{i:'🥅',v:stats.golSubiti,l:'GS'},{i:'📈',v:(stats.differenzaReti>=0?'+':'')+stats.differenzaReti,l:'DR',c:stats.differenzaReti>=0?'#27AE60':'#E74C3C'}];c.innerHTML='<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:24px;"><div><h1 class="page-title">Dashboard '+getSquadraName()+'</h1><p class="page-subtitle">Stagione 2025/26 · '+stats.partiteGiocate+' partite</p></div><button class="btn btn-primary" id="btnNew">+ Nuova Partita</button></div><div class="widgets">'+widgets.map(w=>'<div class="card widget"><div class="widget-value" style="'+(w.c?'color:'+w.c:'')+'">'+w.v+'</div><div class="widget-label">'+w.l+'</div></div>').join('')+'</div><div class="grid-2" style="margin-bottom:20px;"><div class="card"><h3 class="section-title">⚽ Top 5 Marcatori</h3>'+(top.marcatori||[]).map((x,i)=>'<div class="top-player"><span>'+['🥇','🥈','🥉','4°','5°'][i]+'</span><div class="top-player-avatar">'+(x.nome||'?')[0]+'</div><span class="top-player-name">'+x.nome+'</span><span class="top-player-stat">'+x.gol+' Gol</span></div>').join('')+'</div><div class="card"><h3 class="section-title">🅰️ Top 5 Assist</h3>'+(top.assistmen||[]).map((x,i)=>'<div class="top-player"><span>'+['🥇','🥈','🥉','4°','5°'][i]+'</span><div class="top-player-avatar">'+(x.nome||'?')[0]+'</div><span class="top-player-name">'+x.nome+'</span><span class="top-player-stat">'+x.assist+' Assist</span></div>').join('')+'</div></div><div class="grid-2" style="margin-bottom:20px;"><div class="card"><h3 class="section-title">🏃 Top 5 Presenze</h3>'+(top.presenze||[]).map((x,i)=>'<div class="top-player"><span>'+['🥇','🥈','🥉','4°','5°'][i]+'</span><div class="top-player-avatar">'+(x.nome||'?')[0]+'</div><span class="top-player-name">'+x.nome+'</span><span class="top-player-stat">'+x.presenze+' Pres. · '+x.minuti+"'</span></div>").join('')+'</div><div class="card"><h3 class="section-title">📋 Ultimi Risultati</h3>'+(stats.risultati||[]).slice(0,5).map(r=>'<div style="display:flex;align-items:center;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--border);cursor:pointer;" onclick="openMatchDetail(\''+r.id+'\')"><div><span style="font-size:13px;color:var(--gray);">'+formatDateShort(r.dataOra)+'</span><br><strong>vs '+r.avversario+'</strong></div><div style="font-size:18px;font-weight:bold;color:'+(r.golFatti>r.golSubiti?'#27AE60':r.golFatti===r.golSubiti?'#F39C12':'#E74C3C')+';">'+r.golFatti+' - '+r.golSubiti+'</div></div>').join('')+'</div></div><div class="card"><h3 class="section-title">👥 Staff</h3><div style="display:flex;flex-wrap:wrap;gap:16px;">'+['allenatore','dirigente','dirigente2','preparatore_atletico','allenatore_portieri'].map(r=>'<div><strong>'+(r==='allenatore'?'All.':r==='dirigente'?'1° Dir.':r==='dirigente2'?'2° Dir.':r==='preparatore_atletico'?'Prep. Atl.':'All. Port.')+':</strong> '+(s[r]||'N/D')+'</div>').join('')+'</div></div>';document.getElementById('btnNew').addEventListener('click',()=>openMatchForm());}catch(err){c.innerHTML='<div class="error-box">'+err.message+'</div>';}}

// ── ROSA ──
async function loadRoster(){const c=document.getElementById('pageContent');try{const[players,scadenze]=await Promise.all([apiFetch('/squadre/'+squadraId+'/calciatori'),apiFetch('/squadre/'+squadraId+'/scadenze-mediche').catch(()=>[])]);allPlayers=players;renderRoster(c,players,scadenze);}catch(e){c.innerHTML='<div class="error-box">'+e.message+'</div>';}}
function renderRoster(c,players,scadenze){const ruoli=['Portiere','Difensore','Centrocampista','Attaccante'];const plur={Portiere:'Portieri',Difensore:'Difensori',Centrocampista:'Centrocampisti',Attaccante:'Attaccanti'};const byRole={};ruoli.forEach(r=>byRole[r]=players.filter(p=>p.ruolo===r));c.innerHTML='<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:20px;"><div><h1 class="page-title">Rosa '+getSquadraName()+'</h1><p class="page-subtitle">'+players.length+' calciatori · '+ruoli.map(r=>byRole[r].length+' '+plur[r]).join(' · ')+'</p></div><button class="btn btn-primary" id="btnAdd">+ Aggiungi</button></div>'+(scadenze.length>0?'<div class="card" style="margin-bottom:20px;border-left:4px solid #F39C12;"><h3>⚠️ Certificati in scadenza</h3>'+scadenze.map(x=>'<div>'+x.nome+' '+x.cognome+' - '+formatDateShort(x.scadenza)+' ('+x.giorniRimanenti+'gg)</div>').join('')+'</div>':'')+'<div class="roster-toolbar"><input class="search-bar" placeholder="Cerca giocatore..." id="sInput"><select class="filter-select" id="fRuolo"><option value="">Tutti i ruoli</option>'+ruoli.map(r=>'<option value="'+r+'">'+plur[r]+'</option>').join('')+'</select><select class="filter-select" id="fStato"><option value="">Tutti gli stati</option><option value="Attivo">Attivo</option><option value="Infortunato">Infortunato</option></select></div>'+ruoli.map(r=>'<div style="margin-bottom:20px;"><h3 style="font-size:16px;font-weight:600;color:var(--blue);margin-bottom:12px;padding-bottom:8px;border-bottom:2px solid var(--green);">'+plur[r]+' ('+byRole[r].length+')</h3><div class="roster-grid" id="grid'+r+'">'+renderPlayerCards(byRole[r].sort((a,b)=>a.cognome.localeCompare(b.cognome)))+'</div></div>').join('');document.getElementById('btnAdd').addEventListener('click',()=>openPlayerForm());document.getElementById('sInput').addEventListener('input',filterRoster);document.getElementById('fRuolo').addEventListener('change',filterRoster);document.getElementById('fStato').addEventListener('change',filterRoster);document.querySelectorAll('.roster-grid .player-card').forEach(card=>card.addEventListener('click',()=>openPlayerForm(card.dataset.pid)));}
function renderPlayerCards(players){return players.length===0?'<p style="color:var(--gray);grid-column:1/-1;">Nessun calciatore</p>':players.map(p=>'<div class="card player-card" data-pid="'+p.id+'"><div class="player-avatar" style="background:'+getAvatarColor(p.nome)+'">'+p.nome[0]+p.cognome[0]+'</div><div class="player-info"><div class="player-name">'+p.nome+' '+p.cognome+'</div><div class="player-role">'+p.ruolo+' · #'+p.numeroMaglia+'</div><div style="margin-top:6px;"><span class="badge '+(p.stato==='Attivo'?'badge-green':'badge-red')+'">'+p.stato+'</span></div></div></div>').join('');}
function filterRoster(){const s=(document.getElementById('sInput')?.value||'').toLowerCase();const ruolo=document.getElementById('fRuolo')?.value||'';const stato=document.getElementById('fStato')?.value||'';let f=allPlayers;if(s)f=f.filter(p=>(p.nome+' '+p.cognome).toLowerCase().includes(s));if(ruolo)f=f.filter(p=>p.ruolo===ruolo);if(stato)f=f.filter(p=>p.stato===stato);['Portiere','Difensore','Centrocampista','Attaccante'].forEach(ruolo=>{const grid=document.getElementById('grid'+ruolo);if(grid){const filtered=f.filter(p=>p.ruolo===ruolo).sort((a,b)=>a.cognome.localeCompare(b.cognome));grid.innerHTML=renderPlayerCards(filtered);grid.querySelectorAll('.player-card').forEach(card=>card.addEventListener('click',()=>openPlayerForm(card.dataset.pid)));}});}
function openPlayerForm(pid){const p=pid?allPlayers.find(x=>x.id===pid):null;const content='<div class="form-grid"><div class="form-group"><label>Nome</label><input id="pfN" value="'+(p?p.nome:'')+'"></div><div class="form-group"><label>Cognome</label><input id="pfC" value="'+(p?p.cognome:'')+'"></div><div class="form-group"><label>Data Nascita</label><input id="pfD" type="date" value="'+(p&&p.dataNascita?new Date(p.dataNascita).toISOString().split('T')[0]:'')+'"></div><div class="form-group"><label>Telefono</label><input id="pfTel" value="'+(p?p.telefono||'':'')+'"></div><div class="form-group"><label>Data Visita Medica</label><input id="pfVM" type="date" value="'+(p&&p.dataVisitaMedica?p.dataVisitaMedica:'')+'"></div><div class="form-group"><label>Ruolo</label><select id="pfR"><option>Attaccante</option><option>Centrocampista</option><option>Difensore</option><option>Portiere</option></select></div><div class="form-group"><label>N. Maglia</label><input id="pfM" type="number" value="'+(p?p.numeroMaglia||'':'')+'"></div><div class="form-group"><label>Matricola FIGC</label><input id="pfFigc" value="'+(p?p.matricolaFigc||'':'')+'"></div><div class="form-group"><label>Tipo Doc</label><input id="pfTD" value="'+(p?p.tipoDocumento||'':'')+'"></div><div class="form-group"><label>N. Doc</label><input id="pfND" value="'+(p?p.numeroDocumento||'':'')+'"></div><div class="form-group"><label>Rilasciato</label><input id="pfRD" value="'+(p?p.rilasciatoDa||'':'')+'"></div></div>';const footer='<button class="btn btn-secondary" onclick="window._closeModal()">Annulla</button><button class="btn btn-primary" id="saveBtn">Salva</button>';const{closeModal}=createModal(p?'Modifica':'Nuovo',content,footer,'650px');if(p)document.getElementById('pfR').value=p.ruolo;document.getElementById('saveBtn').addEventListener('click',async()=>{showLoading();const d={nome:document.getElementById('pfN').value,cognome:document.getElementById('pfC').value,dataNascita:document.getElementById('pfD').value,telefono:document.getElementById('pfTel').value,dataVisitaMedica:document.getElementById('pfVM').value,ruolo:document.getElementById('pfR').value,numeroMaglia:parseInt(document.getElementById('pfM').value)||1,matricolaFigc:document.getElementById('pfFigc').value,tipoDocumento:document.getElementById('pfTD').value,numeroDocumento:document.getElementById('pfND').value,rilasciatoDa:document.getElementById('pfRD').value};try{if(p)await apiFetch('/calciatori/'+p.id,{method:'PUT',body:JSON.stringify(d)});else await apiFetch('/squadre/'+squadraId+'/calciatori',{method:'POST',body:JSON.stringify(d)});closeModal();loadRoster();}catch(e){alert(e.message);}finally{hideLoading();}});}

// ── CALENDARIO ──
async function loadCalendar(){const c=document.getElementById('pageContent');try{allMatches=await apiFetch('/squadre/'+squadraId+'/partite');const stats=await apiFetch('/squadre/'+squadraId+'/statistiche-complete').catch(()=>({risultati:[]}));const now=new Date();const next=allMatches.find(m=>new Date(m.data_ora)>now);const past=allMatches.filter(m=>m!==next).sort((a,b)=>new Date(b.data_ora)-new Date(a.data_ora));c.innerHTML='<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:24px;"><div><h1 class="page-title">Calendario '+getSquadraName()+'</h1></div><button class="btn btn-primary" id="btnAdd">+ Nuova</button><button class="btn btn-secondary" id="btnImport" style="font-size:13px;margin-left:8px;">📥 Importa CSV</button></div>'+(next?'<div class="card" style="margin-bottom:20px;border-left:4px solid var(--green);background:#E8F8F0;"><h3 class="section-title">⚽ PROSSIMA PARTITA</h3>'+renderMatchCard(next,stats)+'</div>':'')+'<div id="matchList">'+past.map(m=>'<div class="card" style="margin-bottom:12px;">'+renderMatchCard(m,stats)+'</div>').join('')+'</div>';setTimeout(()=>{const btnAdd=document.getElementById('btnAdd');const btnImport=document.getElementById('btnImport');if(btnAdd)btnAdd.addEventListener('click',()=>openMatchForm());if(btnImport)btnImport.addEventListener('click',()=>openImportCSV());document.querySelectorAll('.btn-editm').forEach(b=>b.addEventListener('click',(e)=>{e.stopPropagation();openMatchForm(b.dataset.mid)}));document.querySelectorAll('.btn-del').forEach(b=>b.addEventListener('click',(e)=>{e.stopPropagation();deleteMatch(b.dataset.mid)}));},0);}catch(e){c.innerHTML='<div class="error-box">'+e.message+'</div>';}}
function renderMatchCard(m,stats){const r=(stats?.risultati||[]).find(x=>x.id===m.id);const isPast=new Date(m.data_ora)<new Date();let L='<div class="match-date">'+formatDate(m.data_ora)+'</div><div class="match-teams">'+getSocietaName()+' vs '+m.avversario+'</div><div class="match-info">'+(m.giornata?'Giornata '+m.giornata+' - ':'')+m.competizione+' · '+m.luogo+'</div>';let R='';if(r)R+='<div style="font-size:22px;font-weight:bold;color:'+(r.golFatti>r.golSubiti?'#27AE60':r.golFatti===r.golSubiti?'#F39C12':'#E74C3C')+';cursor:pointer;min-width:50px;text-align:center;" onclick="event.stopPropagation();openMatchDetail(\''+m.id+'\')" title="Clicca per il dettaglio">'+r.golFatti+' - '+r.golSubiti+'</div>';else if(isPast)R+='<span style="color:var(--gray);cursor:pointer;" onclick="event.stopPropagation();openMatchDetail(\''+m.id+'\')">Dettaglio</span>';R+='<button class="btn btn-secondary btn-small" onclick="event.stopPropagation();openConvocation(\''+m.id+'\','+isPast+')">📋 '+(isPast?'Vedi Conv.':'Convoca')+'</button>';R+='<button class="btn btn-secondary btn-small" onclick="event.stopPropagation();openDistinta(\''+m.id+'\')">📄 Distinta</button>';if(!isPast)R+='<button class="btn btn-secondary btn-small" onclick="event.stopPropagation();openFormazioneForm(\''+m.id+'\')">👥 Formazione</button>';R+='<button class="btn btn-secondary btn-small btn-editm" data-mid="'+m.id+'" onclick="event.stopPropagation();">✏️</button>';R+='<button class="btn btn-secondary btn-small btn-danger btn-del" data-mid="'+m.id+'" onclick="event.stopPropagation();">🗑️</button>';return'<div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:12px;"><div style="flex:1;min-width:220px;">'+L+'</div><div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;">'+R+'</div></div>';}
function openMatchForm(mid){const m=mid?allMatches.find(x=>x.id===mid):null;const content='<div class="form-group" style="margin-bottom:12px;"><label>Data e Ora</label><input id="mfD" type="datetime-local" value="'+(m?new Date(m.data_ora).toISOString().slice(0,16):'')+'"></div><div class="form-group" style="margin-bottom:12px;"><label>Avversario</label><input id="mfA" value="'+(m?m.avversario||'':'')+'"></div><div class="form-group" style="margin-bottom:12px;"><label>Luogo</label><select id="mfL"><option'+(m&&m.luogo==='Casa'?' selected':'')+'>Casa</option><option'+(m&&m.luogo==='Trasferta'?' selected':'')+'>Trasferta</option></select></div><div class="form-group" style="margin-bottom:12px;"><label>Competizione</label><input id="mfC" value="'+(m?m.competizione||'':'')+'"></div><div class="form-group"><label>Giornata</label><input id="mfG" type="number" value="'+(m?m.giornata||'':'')+'" style="width:80px;"></div>';const footer='<button class="btn btn-secondary" onclick="window._closeModal()">Annulla</button><button class="btn btn-primary" id="saveBtn">Salva</button>';const{closeModal}=createModal(m?'Modifica':'Nuova Partita',content,footer,'500px');document.getElementById('saveBtn').addEventListener('click',async()=>{const d={dataOra:new Date(document.getElementById('mfD').value).toISOString(),avversario:document.getElementById('mfA').value,luogo:document.getElementById('mfL').value,competizione:document.getElementById('mfC').value,giornata:parseInt(document.getElementById('mfG').value)||null};showLoading();try{if(m)await apiFetch('/partite/'+m.id,{method:'PUT',body:JSON.stringify(d)});else await apiFetch('/squadre/'+squadraId+'/partite',{method:'POST',body:JSON.stringify(d)});closeModal();loadCalendar();}catch(e){alert(e.message);}finally{hideLoading();}});}
async function deleteMatch(id){if(confirm('Eliminare?')){await apiFetch('/partite/'+id,{method:'DELETE'});loadCalendar();}}

// ── DETTAGLIO PARTITA + FORMAZIONE ──
async function openMatchDetail(mid){
  const content='<div id="detailInner"><div class="loading"><div class="spinner"></div>Caricamento...</div></div>';
  const match=allMatches.find(m=>m.id===mid);
  const isFuture=match&&new Date(match.data_ora)>new Date();
  const footer='<button class="btn btn-secondary" onclick="window._closeModal()">Chiudi</button>'+(isFuture?'<button class="btn btn-primary" id="btnFormazione">👥 Formazione</button>':'');
  createModal('📋 Dettaglio Partita',content,footer,'800px');
  if(isFuture)document.getElementById('btnFormazione').addEventListener('click',()=>openFormazioneForm(mid));
  try{
    const d=await apiFetch('/partite/'+mid+'/dettaglio');
    const p=d.partita;
    const eventi=d.eventi||[];
    const golCasa=eventi.filter(e=>e.tipo==='GOAL').length;
    const ammonizioni=eventi.filter(e=>e.tipo==='YELLOW').length;
    const espulsioni=eventi.filter(e=>e.tipo==='RED').length;
    let html='<div style="margin-bottom:16px;"><strong style="font-size:18px;">'+getSocietaName()+' vs '+p.avversario+'</strong></div>';
    html+='<div style="color:var(--gray);margin-bottom:16px;">'+formatDate(p.data_ora)+' · '+p.competizione+' · '+p.luogo+'</div>';
    html+='<div style="display:flex;gap:20px;margin-bottom:20px;flex-wrap:wrap;">';
    html+='<div class="stat-card"><div class="stat-card-value">'+golCasa+'</div><div class="stat-card-label">Gol</div></div>';
    html+='<div class="stat-card"><div class="stat-card-value">'+ammonizioni+'</div><div class="stat-card-label">Ammonizioni</div></div>';
    html+='<div class="stat-card"><div class="stat-card-value">'+espulsioni+'</div><div class="stat-card-label">Espulsioni</div></div>';
    html+='</div>';
    html+='<table style="width:100%;border-collapse:collapse;font-size:14px;"><thead><tr style="background:#F8F9FA;"><th style="padding:10px;">Minuto</th><th style="padding:10px;">Evento</th><th style="padding:10px;">Calciatore</th></tr></thead><tbody>';
    if(eventi.length===0)html+='<tr><td colspan="3" style="padding:20px;text-align:center;color:var(--gray);">Nessun evento registrato</td></tr>';
    else eventi.forEach(e=>{const icona=e.tipo==='GOAL'?'⚽':e.tipo==='ASSIST'?'🅰️':e.tipo==='YELLOW'?'🟨':'🟥';const label=e.tipo==='GOAL'?'Gol':e.tipo==='ASSIST'?'Assist':e.tipo==='YELLOW'?'Ammonizione':'Espulsione';html+='<tr style="border-bottom:1px solid var(--border);"><td style="padding:10px;font-weight:bold;">'+e.minuto+"'</td><td style=\"padding:10px;\">"+icona+' '+label+'</td><td style="padding:10px;">'+e.principale+(e.secondario?' <span style="color:var(--gray);font-size:12px;">(Assist: '+e.secondario+')</span>':'')+'</td></tr>';});
    html+='</tbody></table>';
    
    // Recupera la formazione (solo se non è una partita futura)
    if(!isFuture) {
      try {
        let form = await apiFetch('/partite/'+mid+'/formazione');
        // Arricchisci con nomi da allPlayers se necessario (fallback)
        if (allPlayers.length > 0) {
          form = (form||[]).map(f => {
            if (!f.nome || !f.cognome) {
              const p = allPlayers.find(x => x.id === f.calciatoreId);
              if (p) {
                f.nome = p.nome;
                f.cognome = p.cognome;
              }
            }
            return f;
          });
        }
        if(form && form.length > 0) {
          const titolari = form.filter(f => f.posizione === 'Titolare');
          const panchina = form.filter(f => f.posizione === 'Panchina');
          if (titolari.length === 0 && panchina.length === 0) {
            // Non mostrare nulla se non ci sono né titolari né panchina
          } else {
            html+='<div style="margin-top:20px;"><strong>Formazione</strong></div>';
          if(titolari.length > 0) {
            html+='<div style="font-weight:600;margin-top:8px;">Titolari ('+titolari.length+')</div>';
            html+='<div style="display:flex;flex-wrap:wrap;gap:4px 12px;">';
            titolari.sort((a,b)=>(a.cognome||'').localeCompare(b.cognome||'')).forEach(f=>{
              html+='<span>'+(f.cognome||'')+' '+(f.nome||'')+' ('+f.numeroMaglia+')</span>';
            });
            html+='</div>';
          }
          if(panchina.length > 0) {
            html+='<div style="font-weight:600;margin-top:8px;">Panchina ('+panchina.length+')</div>';
            html+='<div style="display:flex;flex-wrap:wrap;gap:4px 12px;">';
            panchina.sort((a,b)=>(a.cognome||'').localeCompare(b.cognome||'')).forEach(f=>{
              html+='<span>'+(f.cognome||'')+' '+(f.nome||'')+' ('+f.numeroMaglia+')</span>';
            });
            html+='</div>';
          }
          } // chiude else (formazione presente)
        }
      } catch(e) {
        // formazione non disponibile, ignora
      }
    }
    
    document.getElementById('detailInner').innerHTML=html;
  }catch(err){document.getElementById('detailInner').innerHTML='<div class="error-box">Errore nel caricamento del dettaglio.</div>';}
}

async function openFormazioneForm(mid){
  const match=allMatches.find(m=>m.id===mid)||{};
  const[convocazioni,formazioneEsistente,giocatori]=await Promise.all([
    apiFetch('/partite/'+mid+'/convocazioni').catch(()=>[]),
    apiFetch('/partite/'+mid+'/formazione').catch(()=>[]),
    apiFetch('/squadre/'+squadraId+'/calciatori').catch(()=>[])
  ]);
  const convocatiIds=convocazioni.filter(c=>c.presente===true).map(c=>c.calciatoreId);
  // Ordina per ruolo e poi per cognome
  const ruoloOrder=['Portiere','Difensore','Centrocampista','Attaccante'];
  const giocatoriConvocati=giocatori.filter(g=>convocatiIds.includes(g.id)).sort((a,b)=>{
    const ra=ruoloOrder.indexOf(a.ruolo),rb=ruoloOrder.indexOf(b.ruolo);
    if(ra!==rb)return ra-rb;
    return a.cognome.localeCompare(b.cognome);
  });
  const formMap={};
  (formazioneEsistente||[]).forEach(f=>{formMap[f.calciatoreId]=f;});
  let html='<p style="margin-bottom:16px;"><strong>Formazione - '+getSocietaName()+' vs '+match.avversario+'</strong></p>';
  html+='<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;">';
  html+='<div><h4 style="margin-bottom:8px;">Titolari <span id="cntTitolari" style="font-size:12px;color:var(--gray);"></span></h4>';
  giocatoriConvocati.forEach(g=>{
    const f=formMap[g.id];
    const checked=f&&f.posizione==='Titolare'?' checked':'';
    html+='<div style="display:flex;align-items:center;gap:8px;padding:4px 0;"><input type="checkbox"'+checked+' data-pid="'+g.id+'" class="form-check-tit" style="accent-color:var(--green);"><span style="flex:1;">'+g.nome+' '+g.cognome+' <span style="color:var(--gray);font-size:12px;">('+g.ruolo+')</span></span><input type="number" value="'+(f?f.numeroMaglia:g.numeroMaglia)+'" data-pid="'+g.id+'" class="form-num-tit" style="width:50px;padding:4px;" placeholder="N."></div>';
  });
  html+='</div><div><h4 style="margin-bottom:8px;">Panchina <span id="cntRiserve" style="font-size:12px;color:var(--gray);"></span></h4>';
  giocatoriConvocati.forEach(g=>{
    const f=formMap[g.id];
    const checked=f&&f.posizione==='Panchina'?' checked':'';
    html+='<div style="display:flex;align-items:center;gap:8px;padding:4px 0;"><input type="checkbox"'+checked+' data-pid="'+g.id+'" class="form-check-pan" style="accent-color:var(--orange);"><span style="flex:1;">'+g.nome+' '+g.cognome+' <span style="color:var(--gray);font-size:12px;">('+g.ruolo+')</span></span><input type="number" value="'+(f?f.numeroMaglia:g.numeroMaglia)+'" data-pid="'+g.id+'" class="form-num-pan" style="width:50px;padding:4px;" placeholder="N."></div>';
  });
  html+='</div></div>';
  const footer='<button class="btn btn-secondary" onclick="window._closeModal()">Annulla</button><button class="btn btn-primary" id="saveFormBtn">💾 Salva Formazione</button>';
  const{closeModal}=createModal('👥 Formazione',html,footer,'800px');
  // Mutua esclusione e contatori + regole automatiche
  const updateCounters = () => {
    const titChecked = document.querySelectorAll('#currentModal .form-check-tit:checked').length;
    const panChecked = document.querySelectorAll('#currentModal .form-check-pan:checked').length;
    document.getElementById('cntTitolari').textContent = titChecked + '/11 titolari';
    document.getElementById('cntRiserve').textContent = panChecked + ' riserve';
    // Abilita/disabilita pulsante salva
    const saveBtn = document.getElementById('saveFormBtn');
    if (saveBtn) {
      saveBtn.disabled = titChecked !== 11;
      saveBtn.style.opacity = titChecked === 11 ? '1' : '0.5';
    }
    // Blocca la selezione di nuovi titolari se già 11
    document.querySelectorAll('#currentModal .form-check-tit:not(:checked)').forEach(cb => {
      cb.disabled = titChecked >= 11;
    });
  };
  document.querySelectorAll('#currentModal .form-check-tit').forEach(cbTit=>{
    cbTit.addEventListener('change',()=>{
      if(cbTit.checked){
        const pan=document.querySelector('#currentModal .form-check-pan[data-pid="'+cbTit.dataset.pid+'"]');
        if(pan)pan.checked=false;
      } else {
        // Se deselezionato come titolare, automaticamente diventa riserva
        const pan=document.querySelector('#currentModal .form-check-pan[data-pid="'+cbTit.dataset.pid+'"]');
        if(pan)pan.checked=true;
      }
      updateCounters();
    });
  });
  document.querySelectorAll('#currentModal .form-check-pan').forEach(cbPan=>{
    cbPan.addEventListener('change',()=>{
      if(cbPan.checked){
        const tit=document.querySelector('#currentModal .form-check-tit[data-pid="'+cbPan.dataset.pid+'"]');
        if(tit)tit.checked=false;
      }
      updateCounters();
    });
  });
  updateCounters();
  document.getElementById('saveFormBtn').addEventListener('click',async()=>{
    const formazione=[];
    document.querySelectorAll('#currentModal .form-check-tit:checked').forEach(cb=>{
      const pid=cb.dataset.pid;
      const numInput=document.querySelector('#currentModal .form-num-tit[data-pid="'+pid+'"]');
      formazione.push({calciatoreId:pid,numeroMaglia:parseInt(numInput?.value)||giocatoriConvocati.find(g=>g.id===pid)?.numeroMaglia||99,posizione:'Titolare',capitano:false,viceCapitano:false});
    });
    document.querySelectorAll('#currentModal .form-check-pan:checked').forEach(cb=>{
      const pid=cb.dataset.pid;
      const numInput=document.querySelector('#currentModal .form-num-pan[data-pid="'+pid+'"]');
      formazione.push({calciatoreId:pid,numeroMaglia:parseInt(numInput?.value)||giocatoriConvocati.find(g=>g.id===pid)?.numeroMaglia||99,posizione:'Panchina',capitano:false,viceCapitano:false});
    });
    showLoading();
    try {
      await apiFetch('/partite/'+mid+'/formazione',{method:'PUT',body:JSON.stringify({formazione})});
      hideLoading();closeModal();
    } catch(e) {
      hideLoading();
      alert('❌ Errore: '+e.message+'\nIl backend potrebbe non essere raggiungibile.\nVerifica la connessione e riprova.');
    }
  });
}

// ── CONVOCAZIONI, DISTINTA, ALLENAMENTI (batch), IMPORT CSV ──
async function openConvocation(mid,readOnly){
  const match=allMatches.find(m=>m.id===mid)||{};
  const[conv,gioc]=await Promise.all([apiFetch('/partite/'+mid+'/convocazioni').catch(()=>[]),apiFetch('/squadre/'+squadraId+'/calciatori')]);
  const ids=conv.filter(c=>c.presente===true).map(c=>c.calciatoreId);
  const sorted=[...gioc].sort((a,b)=>{const o=['Portiere','Difensore','Centrocampista','Attaccante'];const ra=o.indexOf(a.ruolo),rb=o.indexOf(b.ruolo);if(ra!==rb)return ra-rb;return a.cognome.localeCompare(b.cognome);});
  function buildPdfContent(){
    const checks=document.querySelectorAll('#currentModal .conv-check:checked');
    const list=[];checks.forEach(cb=>{const row=cb.closest('.convocation-item');if(row){const spans=row.querySelectorAll('span');const nc=spans[0]?spans[0].textContent.trim():'';const rm=spans[1]?spans[1].textContent.trim():'';const parti=nc.split(' ');const nome=parti[0]||'';const cognome=parti.slice(1).join(' ')||'';const ruolo=rm.split(' · ')[0]||'';list.push({nome,cognome,ruolo});}});
    list.sort((a,b)=>a.cognome.localeCompare(b.cognome));const dt=new Date(match.data_ora);const ritrovo=new Date(dt.getTime()-75*60000);const giorni=['Domenica','Lunedì','Martedì','Mercoledì','Giovedì','Venerdì','Sabato'];const catYear=dt.getFullYear()-14;
    let html='<div class="t1">CONVOCAZIONE</div><div class="t2">'+getSocietaName()+' - '+catYear+'</div><div class="t3">'+(match.giornata?'Giornata '+match.giornata+' - ':'')+(match.competizione||'')+'</div><div class="info">Partita: <strong>'+getSocietaName()+' - '+match.avversario+'</strong><br>Campo: '+(match.luogo||'')+'<br>Alle ore: '+dt.toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'})+' del giorno: <strong>'+giorni[dt.getDay()]+' '+dt.toLocaleDateString('it-IT')+'</strong><br>Ritrovo alle ore: <strong>'+ritrovo.toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'})+'</strong> al Campo di Giuoco</div><table class="list-table" style="border:2px solid #000;border-collapse:collapse;width:100%;"><thead><tr style="background:#f0f0f0;"><th style="border:1px solid #000;padding:5px 8px;width:35px;">N.</th><th style="border:1px solid #000;padding:5px 8px;">Cognome</th><th style="border:1px solid #000;padding:5px 8px;">Nome</th><th style="border:1px solid #000;padding:5px 8px;width:25px;">P</th></tr></thead><tbody>';
    for(let i=0;i<25;i++){if(i<list.length)html+='<tr><td style="border:1px solid #000;padding:4px 6px;text-align:center;font-weight:bold;">'+(i+1)+'</td><td style="border:1px solid #000;padding:4px 6px;">'+list[i].cognome.toUpperCase()+'</td><td style="border:1px solid #000;padding:4px 6px;">'+list[i].nome+'</td><td style="border:1px solid #000;padding:4px 6px;text-align:center;">'+(list[i].ruolo==='Portiere'?'P':'')+'</td></tr>';else html+='<tr><td style="border:1px solid #000;padding:4px 6px;text-align:center;">'+(i+1)+'</td><td style="border:1px solid #000;padding:4px 6px;"></td><td style="border:1px solid #000;padding:4px 6px;"></td><td style="border:1px solid #000;padding:4px 6px;"></td></tr>';}
    html+='</tbody></table><div class="note">Eventuali assenze vanno comunicate tempestivamente. Si raccomanda il rispetto dell\'orario di convocazione.</div><div class="firma">Il Mister</div>';return html;
  }
  if(readOnly){const convocatiList=conv.filter(c=>c.presente===true).map(c=>({nome:c.nome,cognome:c.cognome,ruolo:gioc.find(g=>g.id===c.calciatoreId)?.ruolo||''}));showConvocationPreview(match,convocatiList);return;}
  const content='<p style="margin-bottom:8px;color:var(--gray);">'+formatDate(match.data_ora)+'</p><div style="display:flex;gap:8px;margin-bottom:12px;"><button class="btn btn-secondary btn-small" id="btnSelAll">✅ Tutti</button><button class="btn btn-secondary btn-small" id="btnDeselAll">❌ Nessuno</button><span style="font-size:12px;color:var(--gray);" id="convCount">'+ids.length+' convocati</span><span id="convWarning" style="color:#E74C3C;font-weight:600;font-size:12px;display:none;"></span></div>'+sorted.map(g=>'<div class="convocation-item"><input type="checkbox"'+(ids.includes(g.id)?' checked':'')+' data-pid="'+g.id+'" class="conv-check" style="width:20px;height:20px;cursor:pointer;accent-color:var(--green);"><div class="player-avatar" style="width:32px;height:32px;font-size:12px;background:'+getAvatarColor(g.nome)+';">'+g.nome[0]+g.cognome[0]+'</div><span style="flex:1;">'+g.nome+' '+g.cognome+'</span><span style="color:var(--gray);font-size:13px;">'+g.ruolo+' · #'+g.numeroMaglia+'</span></div>').join('');
  const footer='<button class="btn btn-secondary" onclick="window._closeModal()">Chiudi</button><button class="btn btn-primary" id="saveBtn">💾 Salva</button><button class="btn btn-primary" id="previewBtn" style="background:#0A1C3A;">📄 Vedi Convocazione</button>';
  const{closeModal}=createModal('📋 Convocazioni - vs '+(match.avversario||'...'),content,footer,'650px');
  document.getElementById('previewBtn').addEventListener('click',()=>{const checks=document.querySelectorAll('#currentModal .conv-check:checked');const convocatiList=[];checks.forEach(cb=>{const row=cb.closest('.convocation-item');if(row){const spans=row.querySelectorAll('span');const nc=spans[0]?spans[0].textContent.trim():'';const rm=spans[1]?spans[1].textContent.trim():'';const parti=nc.split(' ');const nome=parti[0]||'';const cognome=parti.slice(1).join(' ')||'';const ruolo=rm.split(' · ')[0]||'';convocatiList.push({nome,cognome,ruolo});}});if(convocatiList.length===0){alert('Nessun convocato selezionato.');return;}showConvocationPreview(match,convocatiList);});
  function upd(){const checks=document.querySelectorAll('#currentModal .conv-check:checked');const c=checks.length;document.getElementById('convCount').textContent=c+' convocati';const w=document.getElementById('convWarning'),s=document.getElementById('saveBtn');w.style.display='none';s.disabled=false;s.style.opacity='1';if(c>20){w.textContent='⚠️ Max 20!';w.style.display='inline';s.disabled=true;s.style.opacity='0.5';}else if(c<11){w.textContent='⚠️ Minimo 11!';w.style.display='inline';s.disabled=true;s.style.opacity='0.5';}else if(c<16){w.textContent='⚠️ Solo '+c;w.style.display='inline';}}
  document.querySelectorAll('#currentModal .conv-check').forEach(cb=>cb.addEventListener('change',upd));
  document.getElementById('btnSelAll').addEventListener('click',()=>{document.querySelectorAll('#currentModal .conv-check').forEach(cb=>cb.checked=true);upd();});
  document.getElementById('btnDeselAll').addEventListener('click',()=>{document.querySelectorAll('#currentModal .conv-check').forEach(cb=>cb.checked=false);upd();});
  upd();
  document.getElementById('saveBtn').addEventListener('click',async()=>{const checks=document.querySelectorAll('#currentModal .conv-check:checked');if(checks.length>20){alert('⚠️ Max 20 convocabili!');return;}if(checks.length<11){alert('⚠️ Minimo 11 calciatori!');return;}if(checks.length<16&&!confirm('Solo '+checks.length+' convocati. Procedere?'))return;showLoading();for(const cb of document.querySelectorAll('#currentModal .conv-check')){await apiFetch('/partite/'+mid+'/convocazioni',{method:'POST',body:JSON.stringify({calciatoreId:cb.dataset.pid,presente:cb.checked})});}hideLoading();closeModal();alert('✅ Convocazioni salvate!');});
}
